  //
  // In general: (icmp ult x, C1) & (icmp eq (x & Mask), C2) is equivalent to
  // just (icmp eq (x & Mask), C2) when all values satisfying the latter are < C1.
  //
  // Max value from (icmp eq (x & Mask), C2) is C2 | ~Mask
  // If C2 | ~Mask < C1, then all values satisfy (x < C1) and the ult is redundant.
  if (IsAnd && V1 != V2) {
    // Check if we have (icmp ult/ule x, C1) & (icmp eq (x & Mask), C2)
    // where C2 | ~Mask < C1 (or <= C1 for ule)
    auto CheckSubsumedRange = [&](ICmpInst *RangeICmp, Value *RangeV,
                                   const APInt &RangeC, ICmpInst *MaskICmp) {
      Value *MaskedV;
      const APInt *Mask, *MaskedC;
      // Check: (icmp eq (x & Mask), C2) where x = RangeV
      if (match(MaskICmp->getOperand(0),
                m_And(m_Value(MaskedV), m_APInt(Mask))) &&
