          if (MaxVal.ule(RangeC))
            return MaskICmp;
        }
      }
      return static_cast<ICmpInst *>(nullptr);
    };

    if (ICmpInst *Subsumed = CheckSubsumedRange(ICmp1, V1, *C1, ICmp2))
      return Subsumed;
    if (ICmpInst *Subsumed = CheckSubsumedRange(ICmp2, V2, *C2, ICmp1))
      return Subsumed;
  }

  if (V1 != V2)
    return nullptr;"}

